"""
S1 PPE Safety Monitor — Flask Backend
REST API + Socket.IO for real-time alerts
"""
import os
import cv2
import base64
import threading
from datetime import datetime
from flask import Flask, jsonify, request, Response
from flask_socketio import SocketIO, emit
from flask_cors import CORS
from dotenv import load_dotenv
from bson import ObjectId
from pymongo import MongoClient

from detector import PPEDetector
from video_processor import VideoProcessor

load_dotenv()

# ── Config ──────────────────────────────────────────────────────────────────
MONGO_URI = os.getenv("MONGO_URI", "mongodb://localhost:27017")
MONGO_DB  = os.getenv("MONGO_DB",  "ppe_safety")
VIDEO_PATH = os.getenv("VIDEO_PATH", "demo.mp4")
FPS_TARGET = int(os.getenv("FPS_TARGET", "3"))
DEBUG = os.getenv("DEBUG", "true").lower() == "true"

# ── Flask Setup ─────────────────────────────────────────────────────────────
app = Flask(__name__)
app.config["SECRET"] = os.getenv("SECRET", "ppe-safety-secret-key")
CORS(app, resources={r"/*": {"origins": "*"}})
socketio = SocketIO(
    app,
    cors_allowed_origins="*",
    async_mode="eventlet",
    ping_timeout=30,
    ping_interval=10,
)

# ── MongoDB ─────────────────────────────────────────────────────────────────
mongo_client = None
db = None
alerts_collection = None


def init_db():
    global mongo_client, db, alerts_collection
    try:
        mongo_client = MongoClient(MONGO_URI, serverSelectionTimeoutMS=3000)
        mongo_client.admin.command("ping")
        db = mongo_client[MONGO_DB]
        alerts_collection = db["alerts"]
        # Create indexes
        alerts_collection.create_index("timestamp")
        alerts_collection.create_index("camera_id")
        alerts_collection.create_index([("timestamp", -1)])
        print(f"[DB] Connected to MongoDB: {MONGO_DB}")
    except Exception as e:
        print(f"[DB] Warning: MongoDB not available ({e}). Running without persistence.")


# ── Detection Engine ────────────────────────────────────────────────────────
processor = None
detector = PPEDetector()


def on_violation_detected(violations, summary):
    """Callback when PPE violations are found."""
    timestamp = datetime.utcnow().isoformat()

    for v in violations:
        alert = {
            "type": "ppe_violation",
            "timestamp": timestamp,
            "camera_id": "demo-camera",
            "detection": {
                "bbox": v["bbox"],
                "confidence": v["confidence"],
                "class_name": v["class_name"],
                "has_helmet": v["ppe_status"]["has_helmet"],
                "has_vest": v["ppe_status"]["has_vest"],
                "compliant": v["ppe_status"]["compliant"],
            },
            "summary": summary,
        }

        # Persist to MongoDB
        if alerts_collection:
            try:
                alerts_collection.insert_one(alert)
            except Exception as e:
                print(f"[DB] Failed to persist alert: {e}")

        # Emit via WebSocket
        socketio.emit("ppe_alert", alert)


def on_detection_results(frame, detections, summary):
    """Callback on every detection cycle."""
    # Send summary update to dashboard subscribers
    socketio.emit("detection_summary", {
        "summary": summary,
        "timestamp": datetime.utcnow().isoformat(),
        "camera_id": "demo-camera",
    })


# ── Routes ───────────────────────────────────────────────────────────────────

@app.route("/health", methods=["GET"])
def health():
    return jsonify({
        "status": "ok",
        "timestamp": datetime.utcnow().isoformat(),
        "processor_running": processor._running if processor else False,
    })


@app.route("/api/detect", methods=["POST"])
def detect_frame():
    """
    Accept a base64-encoded image, return detection results.
    Body: { "image": "base64...", "camera_id": "cam1" }
    """
    try:
        data = request.get_json()
        image_b64 = data.get("image", "")
        camera_id = data.get("camera_id", "unknown")

        if not image_b64:
            return jsonify({"error": "No image provided"}), 400

        # Decode image
        img_bytes = base64.b64decode(image_b64)
        nparr = __import__("numpy").frombuffer(img_bytes, dtype="uint8")
        frame = cv2.imdecode(nparr, cv2.IMREAD_COLOR)

        if frame is None:
            return jsonify({"error": "Invalid image"}), 400

        # Detect
        annotated, detections, summary, violations = processor.process_single_frame(frame)

        # Annotate frame
        annotated_b64 = VideoProcessor.frame_to_base64(annotated)

        response = {
            "detections": detections,
            "summary": summary,
            "annotated_image": annotated_b64,
            "camera_id": camera_id,
            "timestamp": datetime.utcnow().isoformat(),
        }

        # Log violations to DB
        if violations and alerts_collection:
            for v in violations:
                alerts_collection.insert_one({
                    "type": "ppe_violation",
                    "timestamp": datetime.utcnow().isoformat(),
                    "camera_id": camera_id,
                    "detection": {
                        "bbox": v["bbox"],
                        "confidence": v["confidence"],
                        "has_helmet": v["ppe_status"]["has_helmet"],
                        "has_vest": v["ppe_status"]["has_vest"],
                    },
                })

        return jsonify(response)

    except Exception as e:
        return jsonify({"error": str(e)}), 500


@app.route("/api/summary", methods=["GET"])
def get_summary():
    """Get latest detection summary from running processor."""
    if not processor:
        return jsonify({"error": "Processor not initialized"}), 503

    results = processor.get_latest_results()
    return jsonify({
        **results,
        "timestamp": datetime.utcnow().isoformat(),
    })


@app.route("/api/alerts", methods=["GET"])
def get_alerts():
    """Get recent alerts from MongoDB."""
    if not alerts_collection:
        return jsonify([])

    limit = int(request.args.get("limit", 50))
    cursor = alerts_collection.find(
        {},
        {"_id": 0}
    ).sort("timestamp", -1).limit(limit)

    alerts = list(cursor)
    return jsonify(alerts)


@app.route("/api/alerts/stats", methods=["GET"])
def get_alert_stats():
    """Get aggregated alert statistics."""
    if not alerts_collection:
        return jsonify({"error": "DB not available"}), 503

    from datetime import timedelta
    now = datetime.utcnow()
    last_24h = now - timedelta(hours=24)

    pipeline = [
        {"$match": {"timestamp": {"$gte": last_24h.isoformat()}}},
        {"$group": {
            "_id": None,
            "total": {"$sum": 1},
            "no_helmet": {
                "$sum": {"$cond": [{"$eq": ["$detection.has_helmet", False]}, 1, 0]}
            },
            "no_vest": {
                "$sum": {"$cond": [{"$eq": ["$detection.has_vest", False]}, 1, 0]}
            },
        }}
    ]

    try:
        result = list(alerts_collection.aggregate(pipeline))
        if result:
            stats = result[0]
            del stats["_id"]
            return jsonify(stats)
        return jsonify({"total": 0, "no_helmet": 0, "no_vest": 0})
    except Exception as e:
        return jsonify({"error": str(e)}), 500


@app.route("/api/start", methods=["POST"])
def start_processor():
    """Start the video processor."""
    global processor
    if processor and processor._running:
        return jsonify({"status": "already_running"})

    use_webcam = request.json.get("use_webcam", False) if request.is_json else False
    video_path = request.json.get("video_path", VIDEO_PATH) if request.is_json else VIDEO_PATH

    processor = VideoProcessor(
        video_path=video_path,
        use_webcam=use_webcam,
        fps_target=FPS_TARGET,
    )
    processor.start(
        on_detection=on_detection_results,
        on_violation=on_violation_detected,
    )

    return jsonify({"status": "started", "video_path": video_path, "use_webcam": use_webcam})


@app.route("/api/stop", methods=["POST"])
def stop_processor():
    """Stop the video processor."""
    global processor
    if processor:
        processor.stop()
        return jsonify({"status": "stopped"})
    return jsonify({"status": "not_running"})


# ── Socket.IO Events ────────────────────────────────────────────────────────

@socketio.on("connect")
def on_connect():
    print(f"[WS] Client connected: {request.sid}")
    emit("connected", {"sid": request.sid, "message": "Connected to PPE Safety Monitor"})


@socketio.on("disconnect")
def on_disconnect():
    print(f"[WS] Client disconnected: {request.sid}")


@socketio.on("subscribe")
def on_subscribe(data):
    camera_id = data.get("camera_id", "demo-camera") if data else "demo-camera"
    print(f"[WS] Client {request.sid} subscribed to {camera_id}")
    emit("subscribed", {"camera_id": camera_id})


# ── Startup ─────────────────────────────────────────────────────────────────

if __name__ == "__main__":
    init_db()

    # Auto-start processor with video file if path exists
    default_video = os.path.join(os.path.dirname(__file__), "demo.mp4")
    if os.path.exists(default_video):
        print(f"[START] Auto-starting with video: {default_video}")
        processor = VideoProcessor(video_path=default_video, fps_target=FPS_TARGET)
        processor.start(
            on_detection=on_detection_results,
            on_violation=on_violation_detected,
        )
    else:
        print("[START] No video file found — use /api/start to start processing")
        processor = VideoProcessor()

    print("[APP] PPE Safety Monitor ready on http://0.0.0.0:5000")
    socketio.run(app, host="0.0.0.0", port=5000, debug=DEBUG)

{
  "name": "s1-ppe-safety-frontend",
  "version": "1.0.0",
  "private": true,
  "type": "module",
  "scripts": {
    "dev": "vite --port 3003",
    "build": "vite build",
    "preview": "vite preview"
  },
  "dependencies": {
    "antd": "^5.16.0",
    "react": "^18.3.1",
    "react-dom": "^18.3.1",
    "react-router-dom": "^6.23.0",
    "socket.io-client": "^4.7.5",
    "dayjs": "^1.11.11",
    "axios": "^1.7.2"
  },
  "devDependencies": {
    "@types/react": "^18.3.1",
    "@types/react-dom": "^18.3.0",
    "@vitejs/plugin-react": "^4.3.0",
    "vite": "^5.2.11"
  }
}

import { defineConfig } from 'vite'
import react from '@vitejs/plugin-react'

export default defineConfig({
  plugins: [react()],
  server: {
    port: 3003,
    proxy: {
      '/api': {
        target: 'http://localhost:5000',
        changeOrigin: true,
      },
      '/socket.io': {
        target: 'http://localhost:5000',
        ws: true,
      },
    },
  },
})

import { useState, useEffect, useRef } from 'react'
import { io } from 'socket.io-client'
import {
  Layout, Card, Row, Col, Statistic, Table, Tag, Badge,
  Button, Space, Typography, Alert, Progress, List, Timeline, Tooltip
} from 'antd'
import {
  SafetyOutlined, AlertOutlined, UserOutlined,
  CheckCircleOutlined, StopOutlined, PlayCircleOutlined,
  VideoCameraOutlined, ReloadOutlined
} from '@ant-design/icons'

const { Header, Content, Sider } = Layout
const { Title, Text } = Typography

// ── API helpers ─────────────────────────────────────────────────────────────
const API_BASE = import.meta.env.VITE_API_BASE || ''

async function fetchAPI(path) {
  const res = await fetch(`${API_BASE}${path}`)
  if (!res.ok) throw new Error(`${path} → ${res.status}`)
  return res.json()
}

// ── Stats Card ──────────────────────────────────────────────────────────────
function StatsCard({ title, value, icon, color, suffix, sub }) {
  return (
    <Card size="small" style={{ borderRadius: 12 }}>
      <Statistic
        title={<Text type="secondary" style={{ fontSize: 13 }}>{title}</Text>}
        value={value}
        suffix={suffix}
        valueStyle={{ color, fontSize: 28, fontWeight: 700 }}
        prefix={<span style={{ marginRight: 8 }}>{icon}</span>}
      />
      {sub && <div style={{ marginTop: 4, fontSize: 12, color: '#888' }}>{sub}</div>}
    </Card>
  )
}

// ── Alert Item ───────────────────────────────────────────────────────────────
function AlertItem({ alert }) {
  const d = alert.detection || {}
  const isViolation = !d.compliant
  return (
    <List.Item style={{ padding: '8px 0' }}>
      <Space align="start" style={{ width: '100%' }}>
        <Badge status={isViolation ? 'error' : 'success'} />
        <div style={{ flex: 1 }}>
          <Space>
            {d.has_helmet === false && <Tag color="red">NO HELMET</Tag>}
            {d.has_vest === false && <Tag color="orange">NO VEST</Tag>}
            {d.compliant && <Tag color="green">OK</Tag>}
          </Space>
          <div style={{ fontSize: 11, color: '#999', marginTop: 2 }}>
            {alert.timestamp ? new Date(alert.timestamp).toLocaleTimeString() : '—'}
            {' · conf: '}{d.confidence?.toFixed(2) || '—'}
          </div>
        </div>
      </Space>
    </List.Item>
  )
}

// ── Live Feed Canvas ─────────────────────────────────────────────────────────
function LiveFeedCanvas({ summary }) {
  const canvasRef = useRef(null)
  const [frameSrc, setFrameSrc] = useState(null)
  const intervalRef = useRef(null)

  useEffect(() => {
    // Poll annotated frame from backend every 2s
    intervalRef.current = setInterval(async () => {
      try {
        const data = await fetchAPI('/api/summary')
        if (data.detections?.length > 0) {
          // For demo: show a placeholder visualization on canvas
          const canvas = canvasRef.current
          if (!canvas) return
          const ctx = canvas.getContext('2d')
          const w = canvas.width
          const h = canvas.height

          // Background
          ctx.fillStyle = '#1a1a2e'
          ctx.fillRect(0, 0, w, h)

          // Grid
          ctx.strokeStyle = '#16213e'
          ctx.lineWidth = 1
          for (let i = 0; i < w; i += 40) {
            ctx.beginPath(); ctx.moveTo(i, 0); ctx.lineTo(i, h); ctx.stroke()
          }
          for (let i = 0; i < h; i += 40) {
            ctx.beginPath(); ctx.moveTo(0, i); ctx.lineTo(w, i); ctx.stroke()
          }

          // Draw detection boxes (scaled to canvas)
          const scaleX = w / 1280
          const scaleY = h / 720
          data.detections.forEach(d => {
            const [x1, y1, x2, y2] = d.bbox.map((v, i) => i % 2 === 0 ? v * scaleX : v * scaleY)
            const ppe = d.ppe_status
            ctx.strokeStyle = ppe.compliant ? '#00c853' : '#ff1744'
            ctx.lineWidth = 2
            ctx.strokeRect(x1, y1, x2 - x1, y2 - y1)
            ctx.fillStyle = ppe.compliant ? 'rgba(0,200,83,0.15)' : 'rgba(255,23,68,0.15)'
            ctx.fillRect(x1, y1, x2 - x1, y2 - y1)
            // Label
            ctx.fillStyle = ppe.compliant ? '#00c853' : '#ff1744'
            ctx.font = 'bold 11px monospace'
            const label = ppe.compliant ? '✓ OK' : `✗ ${!ppe.has_helmet ? 'NO-HELMET' : ''} ${!ppe.has_vest ? 'NO-VEST' : ''}`
            ctx.fillText(label.trim(), x1 + 2, y1 - 4)
          })

          // Stats overlay
          const s = data.summary || {}
          ctx.fillStyle = 'rgba(0,0,0,0.7)'
          ctx.fillRect(8, 8, 180, 70)
          ctx.fillStyle = '#fff'
          ctx.font = '12px monospace'
          ctx.fillText(`Persons: ${s.total_persons || 0}`, 16, 28)
          ctx.fillStyle = '#00c853'
          ctx.fillText(`Compliant: ${s.compliant || 0}`, 16, 46)
          ctx.fillStyle = '#ff1744'
          ctx.fillText(`Violations: ${s.violations || 0}`, 16, 64)
        } else {
          // No detections — show empty state
          const canvas = canvasRef.current
          if (!canvas) return
          const ctx = canvas.getContext('2d')
          ctx.fillStyle = '#1a1a2e'
          ctx.fillRect(0, 0, canvas.width, canvas.height)
          ctx.fillStyle = '#555'
          ctx.font = '16px monospace'
          ctx.textAlign = 'center'
          ctx.fillText('▶ Waiting for video stream...', canvas.width / 2, canvas.height / 2)
          ctx.textAlign = 'left'
        }
      } catch {
        // ignore polling errors
      }
    }, 2000)

    return () => clearInterval(intervalRef.current)
  }, [])

  return (
    <div style={{ position: 'relative' }}>
      <canvas
        ref={canvasRef}
        width={640}
        height={360}
        style={{
          width: '100%',
          borderRadius: 12,
          border: '1px solid #333',
          display: 'block',
        }}
      />
      <div style={{
        position: 'absolute', top: 12, right: 12,
        background: 'rgba(0,0,0,0.6)',
        borderRadius: 6, padding: '4px 10px',
        fontSize: 11, color: '#0f0',
        fontFamily: 'monospace',
      }}>
        LIVE · DEMO CAM
      </div>
    </div>
  )
}

// ── Main App ─────────────────────────────────────────────────────────────────
export default function App() {
  const [summary, setSummary] = useState({
    total_persons: 0, compliant: 0, violations: 0,
    no_helmet: 0, no_vest: 0, compliance_rate: 100,
  })
  const [alerts, setAlerts] = useState([])
  const [alertsPage, setAlertsPage] = useState(1)
  const [status, setStatus] = useState('connecting') // connecting | live | stopped
  const [alertStats, setAlertStats] = useState({})
  const socketRef = useRef(null)

  // ── Socket.IO ──────────────────────────────────────────────────────────────
  useEffect(() => {
    const socket = io(API_BASE || window.location.origin, {
      transports: ['websocket', 'polling'],
      reconnectionAttempts: 5,
      reconnectionDelay: 2000,
    })

    socketRef.current = socket

    socket.on('connect', () => {
      console.log('[WS] Connected')
      socket.emit('subscribe', { camera_id: 'demo-camera' })
      setStatus('live')
    })

    socket.on('disconnect', () => {
      console.log('[WS] Disconnected')
      setStatus('stopped')
    })

    socket.on('detection_summary', (data) => {
      if (data.summary) setSummary(data.summary)
    })

    socket.on('ppe_alert', (alert) => {
      setAlerts(prev => [alert, ...prev].slice(0, 100))
      // Play sound
      try {
        const audio = new Audio('data:audio/wav;base64,')
        audio.volume = 0.3
        audio.play().catch(() => {})
      } catch {}
    })

    socket.on('connected', (data) => console.log('[WS] Server ack:', data))

    return () => socket.disconnect()
  }, [])

  // ── Poll alerts ────────────────────────────────────────────────────────────
  useEffect(() => {
    const loadAlerts = async () => {
      try {
        const [alertsData, statsData] = await Promise.all([
          fetchAPI('/api/alerts?limit=20'),
          fetchAPI('/api/alerts/stats'),
        ])
        if (Array.isArray(alertsData)) setAlerts(alertsData)
        if (statsData) setAlertStats(statsData)
      } catch {}
    }
    loadAlerts()
    const interval = setInterval(loadAlerts, 10000)
    return () => clearInterval(interval)
  }, [])

  const handleStart = async () => {
    try {
      await fetch(`${API_BASE}/api/start`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.json({}),
      })
      setStatus('live')
    } catch {}
  }

  const complianceColor = summary.compliance_rate >= 80 ? '#52c41a'
    : summary.compliance_rate >= 50 ? '#faad14'
    : '#ff4d4f'

  return (
    <Layout style={{ minHeight: '100vh', background: '#0f0f1a' }}>
      {/* ── Header ── */}
      <Header style={{
        background: '#1a1a2e',
        borderBottom: '1px solid #2a2a4a',
        display: 'flex', alignItems: 'center', justifyContent: 'space-between',
        padding: '0 24px',
      }}>
        <Space>
          <SafetyOutlined style={{ fontSize: 24, color: '#faad14' }} />
          <Title level={4} style={{ color: '#fff', margin: 0 }}>
            PPE Safety Monitor
          </Title>
          <Badge
            status={status === 'live' ? 'processing' : 'error'}
            text={<Text style={{ color: status === 'live' ? '#52c41a' : '#ff4d4f', fontSize: 12 }}>
              {status === 'live' ? 'LIVE' : status === 'connecting' ? 'CONNECTING' : 'STOPPED'}
            </Text>}
          />
        </Space>
        <Space>
          <Tooltip title="Reload alerts">
            <Button icon={<ReloadOutlined />} onClick={() => {
              fetchAPI('/api/alerts?limit=20').then(d => Array.isArray(d) && setAlerts(d))
            }}>
              Reload
            </Button>
          </Tooltip>
          {status !== 'live' && (
            <Button
              type="primary"
              icon={<PlayCircleOutlined />}
              onClick={handleStart}
              style={{ background: '#faad14', borderColor: '#faad14' }}
            >
              Start Detection
            </Button>
          )}
        </Space>
      </Header>

      <Layout>
        {/* ── Main Content ── */}
        <Content style={{ padding: 20, background: '#0f0f1a' }}>
          {/* Stats Row */}
          <Row gutter={[16, 16]} style={{ marginBottom: 20 }}>
            <Col xs={24} sm={12} md={6}>
              <StatsCard
                title="Tổng người phát hiện"
                value={summary.total_persons}
                icon={<UserOutlined />}
                color="#1890ff"
              />
            </Col>
            <Col xs={24} sm={12} md={6}>
              <StatsCard
                title="Tuân thủ (✓)"
                value={summary.compliant}
                icon={<CheckCircleOutlined />}
                color="#52c41a"
              />
            </Col>
            <Col xs={24} sm={12} md={6}>
              <StatsCard
                title="Vi phạm (✗)"
                value={summary.violations}
                icon={<StopOutlined />}
                color="#ff4d4f"
                sub={
                  summary.no_helmet > 0 ? `• Không mũ: ${summary.no_helmet}` : null
                }
              />
            </Col>
            <Col xs={24} sm={12} md={6}>
              <Card size="small" style={{ borderRadius: 12 }}>
                <Statistic
                  title={<Text type="secondary" style={{ fontSize: 13 }}>Tỷ lệ tuân thủ</Text>}
                  value={summary.compliance_rate}
                  suffix="%"
                  valueStyle={{ color: complianceColor, fontSize: 28, fontWeight: 700 }}
                  prefix={<SafetyOutlined style={{ marginRight: 8 }} />}
                />
                <Progress
                  percent={summary.compliance_rate}
                  showInfo={false}
                  strokeColor={complianceColor}
                  style={{ marginTop: 8 }}
                />
              </Card>
            </Col>
          </Row>

          {/* Live Feed + Alert Panel */}
          <Row gutter={[16, 16]}>
            <Col xs={24} lg={14}>
              <Card
                title={
                  <Space>
                    <VideoCameraOutlined />
                    Camera Feed — Demo
                  </Space>
                }
                style={{ background: '#1a1a2e', border: '1px solid #2a2a4a' }}
                styles={{ header: { color: '#fff', borderBottom: '1px solid #2a2a4a' } }}
              >
                <LiveFeedCanvas summary={summary} />
                <Alert
                  message="Demo mode — sử dụng video file. Kết nối IP camera thực tế qua /api/detect endpoint."
                  type="info"
                  showIcon
                  style={{ marginTop: 12 }}
                />
              </Card>
            </Col>

            <Col xs={24} lg={10}>
              <Card
                title={
                  <Space>
                    <AlertOutlined style={{ color: '#ff4d4f' }} />
                    Cảnh báo thời gian thực
                    <Badge count={alerts.length} style={{ backgroundColor: '#ff4d4f' }} />
                  </Space>
                }
                style={{ background: '#1a1a2e', border: '1px solid #2a2a4a', height: '100%' }}
                styles={{ header: { color: '#fff', borderBottom: '1px solid #2a2a4a' } }}
                bodyStyle={{ maxHeight: 500, overflow: 'auto' }}
              >
                {alerts.length === 0 ? (
                  <div style={{ textAlign: 'center', padding: 40, color: '#555' }}>
                    <SafetyOutlined style={{ fontSize: 48, marginBottom: 12 }} />
                    <div>Không có cảnh báo nào</div>
                    <div style={{ fontSize: 12, marginTop: 4 }}>Hệ thống đang hoạt động bình thường</div>
                  </div>
                ) : (
                  <List
                    dataSource={alerts}
                    renderItem={(item) => <AlertItem alert={item} />}
                    locale={{ emptyText: 'Không có cảnh báo' }}
                  />
                )}
              </Card>
            </Col>
          </Row>
        </Content>

        {/* ── Sidebar ── */}
        <Sider
          width={240}
          style={{ background: '#1a1a2e', borderLeft: '1px solid #2a2a4a', padding: 16 }}
        >
          <Title level={5} style={{ color: '#fff' }}>Thống kê 24h</Title>
          <Space direction="vertical" style={{ width: '100%' }} size={12}>
            <Card size="small" style={{ background: '#16213e' }}>
              <Statistic
                title={<Text style={{ color: '#aaa', fontSize: 12 }}>Tổng cảnh báo</Text>}
                value={alertStats.total || alerts.length}
                valueStyle={{ color: '#fff', fontSize: 24 }}
              />
            </Card>
            <Card size="small" style={{ background: '#16213e' }}>
              <Statistic
                title={<Text style={{ color: '#aaa', fontSize: 12 }}>Không đội mũ</Text>}
                value={alertStats.no_helmet || 0}
                valueStyle={{ color: '#ff4d4f', fontSize: 24 }}
              />
            </Card>
            <Card size="small" style={{ background: '#16213e' }}>
              <Statistic
                title={<Text style={{ color: '#aaa', fontSize: 12 }}>Không áo phản quang</Text>}
                value={alertStats.no_vest || 0}
                valueStyle={{ color: '#faad14', fontSize: 24 }}
              />
            </Card>

            <div style={{ marginTop: 16 }}>
              <Title level={5} style={{ color: '#fff' }}>Camera</Title>
              <Card size="small" style={{ background: '#16213e' }}>
                <Space>
                  <Badge status="success" />
                  <Text style={{ color: '#aaa', fontSize: 13 }}>demo-camera</Text>
                </Space>
                <div style={{ fontSize: 11, color: '#666', marginTop: 4 }}>1280×720 · YOLOv8n</div>
              </Card>
            </div>
          </Space>
        </Sider>
      </Layout>
    </Layout>
  )
}

