import { useState, useEffect, useRef } from 'react'
import { io } from 'socket.io-client'
import {
  Layout, Card, Row, Col, Statistic, Tag, Badge,
  Button, Space, Typography, Alert, Progress, List, Tooltip
} from 'antd'
import {
  SafetyOutlined, AlertOutlined, UserOutlined,
  CheckCircleOutlined, StopOutlined, PlayCircleOutlined,
  VideoCameraOutlined, ReloadOutlined, VideoAddOutlined
} from '@ant-design/icons'

const { Header, Content, Sider } = Layout
const { Title, Text } = Typography

// ── API helpers ─────────────────────────────────────────────────────────────
const API_BASE = import.meta.env.VITE_API_BASE || ''

async function fetchAPI(path) {
  const res = await fetch(`${API_BASE}${path}`)
  if (!res.ok) throw new Error(`${path} → ${res.status}`)
  return res.json()
}

// ── Stats Card ──────────────────────────────────────────────────────────────
function StatsCard({ title, value, icon, color, sub }) {
  return (
    <Card size="small" style={{ borderRadius: 12 }}>
      <Statistic
        title={<Text type="secondary" style={{ fontSize: 13 }}>{title}</Text>}
        value={value}
        valueStyle={{ color, fontSize: 28, fontWeight: 700 }}
        prefix={<span style={{ marginRight: 8 }}>{icon}</span>}
      />
      {sub && <div style={{ marginTop: 4, fontSize: 12, color: '#888' }}>{sub}</div>}
    </Card>
  )
}

// ── Alert Item ───────────────────────────────────────────────────────────────
function AlertItem({ alert }) {
  const d = alert.detection || {}
  const isViolation = !d.compliant
  return (
    <List.Item style={{ padding: '8px 0' }}>
      <Space align="start" style={{ width: '100%' }}>
        <Badge status={isViolation ? 'error' : 'success'} />
        <div style={{ flex: 1 }}>
          <Space>
            {d.has_helmet === false && <Tag color="red">NO HELMET</Tag>}
            {d.has_vest === false && <Tag color="orange">NO VEST</Tag>}
            {d.compliant && <Tag color="green">OK</Tag>}
          </Space>
          <div style={{ fontSize: 11, color: '#999', marginTop: 2 }}>
            {alert.timestamp ? new Date(alert.timestamp).toLocaleTimeString() : '—'}
            {' · conf: '}{d.confidence?.toFixed(2) || '—'}
          </div>
        </div>
      </Space>
    </List.Item>
  )
}

// ── Video Feed — Shows actual annotated frames from backend ──────────────────
function VideoFeed() {
  const [imgSrc, setImgSrc] = useState(null)
  const [lastUpdate, setLastUpdate] = useState(null)
  const [error, setError] = useState(null)
  const [frameCount, setFrameCount] = useState(0)
  const [summary, setSummary] = useState(null)
  const intervalRef = useRef(null)
  const imgRef = useRef(null)

  useEffect(() => {
    // Poll annotated frame + summary from backend every 500ms
    intervalRef.current = setInterval(async () => {
      try {
        // Fetch annotated frame
        const frameRes = await fetch(`${API_BASE}/api/frame`, { cache: 'no-cache' })
        if (frameRes.ok) {
          const blob = await frameRes.blob()
          const url = URL.createObjectURL(blob)
          setImgSrc(url)
          setLastUpdate(new Date().toLocaleTimeString())
          setError(null)
          setFrameCount(c => c + 1)
        }
      } catch (e) {
        // Silently ignore polling errors
      }

      try {
        // Fetch latest summary
        const summaryRes = await fetch(`${API_BASE}/api/summary`)
        if (summaryRes.ok) {
          const data = await summaryRes.json()
          if (data.summary && Object.keys(data.summary).length > 0) {
            setSummary(data.summary)
          }
        }
      } catch {}
    }, 500)

    return () => {
      clearInterval(intervalRef.current)
      if (intervalRef.current?.imgSrc) {
        URL.revokeObjectURL(imgSrc)
      }
    }
  }, [])

  const complianceColor = summary
    ? (summary.compliance_rate >= 80 ? '#52c41a'
      : summary.compliance_rate >= 50 ? '#faad14' : '#ff4d4f')
    : '#888'

  return (
    <div style={{ position: 'relative', borderRadius: 12, overflow: 'hidden', background: '#000' }}>
      {/* Actual video frame from backend */}
      {imgSrc ? (
        <img
          ref={imgRef}
          src={imgSrc}
          alt="Live detection feed"
          style={{
            width: '100%',
            display: 'block',
            minHeight: 360,
            background: '#000',
          }}
        />
      ) : (
        <div style={{
          width: '100%',
