import { useState, useEffect, useRef } from 'react'
import { io } from 'socket.io-client'
import {
  Layout, Card, Row, Col, Statistic, Tag, Badge,
  Button, Space, Typography, Alert, Progress, List, Tooltip
} from 'antd'
import {
  SafetyOutlined, AlertOutlined, UserOutlined,
  CheckCircleOutlined, StopOutlined, PlayCircleOutlined,
  VideoCameraOutlined, ReloadOutlined, CameraOutlined, LoadingOutlined
} from '@ant-design/icons'

const { Header, Content, Sider } = Layout
const { Title, Text } = Typography

const API_BASE = import.meta.env.VITE_API_BASE || ''
const VIDEO_URL = `${API_BASE}/video/demo.mp4`

async function fetchAPI(path) {
  const res = await fetch(`${API_BASE}${path}`)
  if (!res.ok) throw new Error(`${path} → ${res.status}`)
  return res.json()
}

function StatsCard({ title, value, icon, color, sub }) {
  return (
    <Card size="small" style={{ borderRadius: 12 }}>
      <Statistic
        title={<Text type="secondary" style={{ fontSize: 13 }}>{title}</Text>}
        value={value}
        valueStyle={{ color, fontSize: 28, fontWeight: 700 }}
        prefix={<span style={{ marginRight: 8 }}>{icon}</span>}
      />
      {sub && <div style={{ marginTop: 4, fontSize: 12, color: '#888' }}>{sub}</div>}
    </Card>
  )
}

function AlertItem({ alert }) {
  const d = alert.detection || {}
  const isViolation = !d.compliant
  return (
    <List.Item style={{ padding: '8px 0' }}>
      <Space align="start" style={{ width: '100%' }}>
        <Badge status={isViolation ? 'error' : 'success'} />
        <div style={{ flex: 1 }}>
          <Space>
            {d.has_helmet === false && <Tag color="red">NO HELMET</Tag>}
            {d.has_vest === false && <Tag color="orange">NO VEST</Tag>}
            {d.compliant && <Tag color="green">OK</Tag>}
          </Space>
          <div style={{ fontSize: 11, color: '#999', marginTop: 2 }}>
            {alert.timestamp ? new Date(alert.timestamp).toLocaleTimeString() : '—'}
            {' · conf: '}{d.confidence?.toFixed(2) || '—'}
          </div>
        </div>
      </Space>
    </List.Item>
  )
}

// ── Video Player with Detection Overlay ──────────────────────────────────────
function VideoPlayer({ onSummaryUpdate }) {
  const videoRef = useRef(null)
  const canvasRef = useRef(null)
  const [detections, setDetections] = useState([])
  const [summary, setSummary] = useState(null)
  const [videoReady, setVideoReady] = useState(false)
  const [videoError, setVideoError] = useState(null)
  const [lastUpdate, setLastUpdate] = useState(null)
  const [playing, setPlaying] = useState(false)
  const animationRef = useRef(null)

  // ── Draw boxes on canvas overlay ─────────────────────────────────────────
  const drawDetections = useRef(null)

  // ── Sync detections with video ────────────────────────────────────────────
  useEffect(() => {
    const video = videoRef.current
    const canvas = canvasRef.current
    if (!video || !canvas) return

    const ctx = canvas.getContext('2d')

    const draw = () => {
      if (!video || !ctx) return

      // Match canvas size to video display size
      const vw = video.offsetWidth || 640
      const vh = video.offsetHeight || 360

      if (canvas.width !== vw || canvas.height !== vh) {
        canvas.width = vw
        canvas.height = vh
      }

      ctx.clearRect(0, 0, canvas.width, canvas.height)

      const s = summary || {}
      const dets = detections || []

      // Scale factors (video is 1280x720)
      const scaleX = canvas.width / 1280
      const scaleY = canvas.height / 720

      dets.forEach(d => {
        const [x1, y1, x2, y2] = d.bbox
        const sx1 = x1 * scaleX, sy1 = y1 * scaleY
        const sx2 = x2 * scaleX, sy2 = y2 * scaleY
        const sw = sx2 - sx1, sh = sy2 - sy1
        const ppe = d.ppe_status

        const color = ppe.compliant ? '#00c853' : '#ff1744'

        // Box
        ctx.strokeStyle = color
        ctx.lineWidth = 2
        ctx.strokeRect(sx1, sy1, sw, sh)

        // Fill
        ctx.fillStyle = ppe.compliant
          ? 'rgba(0,200,83,0.12)'
          : 'rgba(255,23,68,0.18)'
        ctx.fillRect(sx1, sy1, sw, sh)

        // Label
        const label = ppe.compliant
          ? 'OK'
          : `${!ppe.has_helmet ? 'NO-HELMET' : ''} ${!ppe.has_vest ? 'NO-VEST' : ''}`.trim()
        ctx.fillStyle = color
        ctx.font = 'bold 11px monospace'
        const tw = ctx.measureText(label).width
        ctx.fillStyle = 'rgba(0,0,0,0.7)'
        ctx.fillRect(sx1, sy1 - 18, tw + 8, 17)
        ctx.fillStyle = color
        ctx.fillText(label, sx1 + 4, sy1 - 5)
      })

      animationRef.current = requestAnimationFrame(draw)
    }

    // Poll summary + detections
    const poll = setInterval(async () => {
      try {
        const data = await fetchAPI('/api/summary')
        if (data.summary) {
          setSummary(data.summary)
          onSummaryUpdate?.(data.summary)
        }
        if (data.detections) {
          setDetections(data.detections)
        }
        setLastUpdate(new Date().toLocaleTimeString())
      } catch {}
    }, 500)

    draw()

    return () => {
      clearInterval(poll)
      if (animationRef.current) cancelAnimationFrame(animationRef.current)
    }
  }, [summary, detections])

  const complianceColor = summary
    ? (summary.compliance_rate >= 80 ? '#52c41a'
      : summary.compliance_rate >= 50 ? '#faad14' : '#ff4d4f')
    : '#888'

  return (
    <div style={{ position: 'relative', borderRadius: 12, overflow: 'hidden', background: '#000' }}>
      {/* HTML5 Video */}
      <div style={{ position: 'relative', lineHeight: 0 }}>
        <video
          ref={videoRef}
          src={VIDEO_URL}
          controls
          autoPlay
          loop
          muted
          playsInline
          style={{
            width: '100%',
            display: 'block',
            background: '#000',
          }}
          onCanPlay={() => setVideoReady(true)}
          onError={(e) => setVideoError('Không thể tải video')}
          onPlay={() => setPlaying(true)}
          onPause={() => setPlaying(false)}
        />

        {/* Canvas overlay for bounding boxes */}
        <canvas
          ref={canvasRef}
          style={{
            position: 'absolute',
            top: 0,
            left: 0,
            width: '100%',
            height: '100%',
            pointerEvents: 'none',
          }}
        />
      </div>

      {/* HUD — top right */}
      <div style={{
        position: 'absolute', top: 12, right: 12,
        background: 'rgba(0,0,0,0.72)',
        borderRadius: 6, padding: '6px 12px',
        fontSize: 11, color: '#0f0',
        fontFamily: 'monospace',
      }}>
        {playing ? '● LIVE' : '⏸ PAUSED'} · Edge+Blob
      </div>

      {/* HUD — top left */}
      <div style={{
        position: 'absolute', top: 12, left: 12,
        background: 'rgba(0,0,0,0.6)',
        borderRadius: 6, padding: '4px 10px',
        fontSize: 10, color: '#aaa',
        fontFamily: 'monospace',
      }}>
        Cập nhật: {lastUpdate || '...'}
      </div>

      {/* HUD — bottom left stats */}
      {summary && (
        <div style={{
          position: 'absolute', bottom: 12, left: 12,
          background: 'rgba(0,0,0,0.75)',
          borderRadius: 8, padding: '10px 14px',
          fontFamily: 'monospace', fontSize: 12,
        }}>
          <div style={{ color: '#fff', marginBottom: 4 }}>
            👤 {summary.total_persons || 0} phát hiện
          </div>
          <div style={{ color: '#52c41a' }}>
            ✅ Tuân thủ: {summary.compliant || 0}
          </div>
          <div style={{ color: '#ff4d4f' }}>
            ❌ Vi phạm: {summary.violations || 0}
          </div>
          <div style={{ color: complianceColor, marginTop: 4 }}>
            📊 Tỷ lệ: {summary.compliance_rate || 0}%
          </div>
        </div>
      )}

      {/* Error / Loading state */}
      {videoError && (
        <div style={{
          position: 'absolute', inset: 0,
          display: 'flex', alignItems: 'center', justifyContent: 'center',
          background: 'rgba(0,0,0,0.8)', color: '#ff4d4f',
        }}>
          {videoError}
        </div>
      )}
      {!videoReady && !videoError && (
        <div style={{
          position: 'absolute', inset: 0,
          display: 'flex', alignItems: 'center', justifyContent: 'center',
          background: 'rgba(0,0,0,0.7)', color: '#aaa',
          flexDirection: 'column', gap: 8,
        }}>
          <LoadingOutlined style={{ fontSize: 32 }} />
          <span>Đang tải video...</span>
        </div>
      )}
    </div>
  )
}

