          <Space direction="vertical" style={{ width: '100%' }} size={12}>
            <Card size="small" style={{ background: '#16213e' }}>
              <Statistic title={<Text style={{ color: '#aaa', fontSize: 12 }}>Tổng cảnh báo</Text>}
                value={alertStats.total || alerts.length} valueStyle={{ color: '#fff', fontSize: 24 }} />
            </Card>
            <Card size="small" style={{ background: '#16213e' }}>
              <Statistic title={<Text style={{ color: '#aaa', fontSize: 12 }}>Không đội mũ</Text>}
                value={alertStats.no_helmet || 0} valueStyle={{ color: '#ff4d4f', fontSize: 24 }} />
            </Card>
            <Card size="small" style={{ background: '#16213e' }}>
              <Statistic title={<Text style={{ color: '#aaa', fontSize: 12 }}>Không áo phản quang</Text>}
                value={alertStats.no_vest || 0} valueStyle={{ color: '#faad14', fontSize: 24 }} />
            </Card>
