              <Card size="small" style={{ background: '#16213e' }}>
                <Space><Badge status="success" /><Text style={{ color: '#aaa', fontSize: 13 }}>demo-camera</Text></Space>
                <div style={{ fontSize: 11, color: '#666', marginTop: 4 }}>1280×720 · Edge+Blob</div>
              </Card>
            </div>
          </Space>
        </Sider>
      </Layout>
    </Layout>
