// ── Video Player ───────────────────────────────────────────────────────────────
function VideoPlayer({ onSummaryUpdate }) {
  const videoRef = useRef(null)
  const canvasRef = useRef(null)
  const [detections, setDetections] = useState([])
  const [summary, setSummary] = useState(null)
  const [videoReady, setVideoReady] = useState(false)
  const [videoError, setVideoError] = useState(null)
  const [playing, setPlaying] = useState(false)
  const animRef = useRef(null)

  // Poll detections
  useEffect(() => {
    const poll = setInterval(async () => {
      try {
        const data = await fetchAPI('/api/summary')
        if (data.summary) {
          setSummary(data.summary)
          onSummaryUpdate?.(data.summary)
        }
        if (data.detections) setDetections(data.detections)
      } catch {}
    }, 500)
    return () => clearInterval(poll)
  }, [])

  // Draw overlay
  useEffect(() => {
    const video = videoRef.current
    const canvas = canvasRef.current
    if (!video || !canvas) return
    const ctx = canvas.getContext('2d')

    const draw = () => {
      if (!video || !ctx) return
      const vw = video.offsetWidth || 640
      const vh = video.offsetHeight || 360
      if (canvas.width !== vw || canvas.height !== vh) {
        canvas.width = vw; canvas.height = vh
      }
      ctx.clearRect(0, 0, canvas.width, canvas.height)
      const sx = canvas.width / 1280
      const sy = canvas.height / 720

      detections.forEach(d => {
        const [x1, y1, x2, y2] = d.bbox
        const px1 = x1 * sx, py1 = y1 * sy, px2 = x2 * sx, py2 = y2 * sy
        const pw = px2 - px1, ph = py2 - py1
        const ok = d.ppe_status.compliant
        const col = ok ? '#00c853' : '#ff1744'
        ctx.strokeStyle = col; ctx.lineWidth = 2
        ctx.strokeRect(px1, py1, pw, ph)
        ctx.fillStyle = ok ? 'rgba(0,200,83,0.12)' : 'rgba(255,23,68,0.18)'
        ctx.fillRect(px1, py1, pw, ph)
        const label = ok ? 'OK' : `${!d.ppe_status.has_helmet ? 'NO-HELMET' : ''} ${!d.ppe_status.has_vest ? 'NO-VEST' : ''}`.trim()
        ctx.font = 'bold 11px monospace'
        const tw = ctx.measureText(label).width
        ctx.fillStyle = 'rgba(0,0,0,0.7)'
        ctx.fillRect(px1, py1 - 18, tw + 8, 17)
        ctx.fillStyle = col
        ctx.fillText(label, px1 + 4, py1 - 5)
      })

      animRef.current = requestAnimationFrame(draw)
    }
    draw()
    return () => { if (animRef.current) cancelAnimationFrame(animRef.current) }
  }, [detections])

  const col = summary?.compliance_rate >= 80 ? '#52c41a'
    : summary?.compliance_rate >= 50 ? '#faad14' : '#ff4d4f'

  return (
    <div style={{ display: 'flex', flexDirection: 'column', gap: 12 }}>

      {/* ── TOP: Real Video + Boxes ── */}
      <div style={{ position: 'relative', borderRadius: 12, overflow: 'hidden', background: '#000' }}>
        <div style={{ position: 'relative', lineHeight: 0 }}>
          <video
            ref={videoRef}
            src={VIDEO_URL}
            controls autoPlay loop muted playsInline
            style={{ width: '100%', display: 'block' }}
            onCanPlay={() => setVideoReady(true)}
            onError={() => setVideoError('Lỗi tải video')}
            onPlay={() => setPlaying(true)}
            onPause={() => setPlaying(false)}
          />
          <canvas
            ref={canvasRef}
            style={{ position: 'absolute', top: 0, left: 0, width: '100%', height: '100%', pointerEvents: 'none' }}
          />
        </div>

        <div style={{
          position: 'absolute', top: 10, right: 10,
          background: 'rgba(0,0,0,0.7)', borderRadius: 6, padding: '4px 10px',
          fontSize: 10, color: '#0f0', fontFamily: 'monospace',
        }}>
          {playing ? '● LIVE' : '⏸ PAUSED'}
        </div>
        <div style={{
          position: 'absolute', top: 10, left: 10,
          background: 'rgba(0,0,0,0.6)', borderRadius: 6, padding: '4px 10px',
          fontSize: 10, color: '#aaa', fontFamily: 'monospace',
        }}>
          📹 VIDEO THỰC
        </div>

        {videoError && (
          <div style={{
            position: 'absolute', inset: 0, display: 'flex', alignItems: 'center',
            justifyContent: 'center', background: 'rgba(0,0,0,0.8)', color: '#ff4d4f',
          }}>
            {videoError}
          </div>
        )}
        {!videoReady && !videoError && (
          <div style={{
            position: 'absolute', inset: 0, display: 'flex', alignItems: 'center',
            justifyContent: 'center', background: 'rgba(0,0,0,0.7)', color: '#aaa',
            flexDirection: 'column', gap: 8,
          }}>
            <LoadingOutlined style={{ fontSize: 32 }} />
            <span>Đang tải video...</span>
          </div>
        )}

        {/* Stats overlay bottom */}
        {summary && (
          <div style={{
            position: 'absolute', bottom: 10, left: 10,
            background: 'rgba(0,0,0,0.8)', borderRadius: 8, padding: '8px 12px',
            fontFamily: 'monospace', fontSize: 11,
          }}>
            <div style={{ color: '#fff' }}>👤 {summary.total_persons || 0} phát hiện</div>
            <div style={{ color: '#52c41a' }}>✅ {summary.compliant || 0} <span style={{ color: '#ff4d4f' }}>❌ {summary.violations || 0}</span></div>
            <div style={{ color: col }}>📊 {summary.compliance_rate || 0}%</div>
          </div>
        )}
      </div>

      {/* ── BOTTOM: Annotated Frame ── */}
      <div>
        <div style={{ fontSize: 11, color: '#666', marginBottom: 6, fontFamily: 'monospace', paddingLeft: 4 }}>
          📷 KẾT QUẢ NHẬN DIỆN (Frame từ Backend)
        </div>
        <AnnotatedFrame summary={summary} />
      </div>

    </div>
  )
}

