import { useState, useEffect, useRef } from 'react'
import { io } from 'socket.io-client'
import {
  Layout, Card, Row, Col, Statistic, Tag, Badge,
  Button, Space, Typography, Alert, Progress, List, Tooltip, Upload, message, Modal
} from 'antd'
import {
  SafetyOutlined, AlertOutlined, UserOutlined,
  CheckCircleOutlined, StopOutlined,
  VideoCameraOutlined, ReloadOutlined, CameraOutlined,
  LoadingOutlined, UploadOutlined, CloudUploadOutlined
} from '@ant-design/icons'

const { Header, Content, Sider } = Layout
const { Title, Text } = Typography

const API_BASE = import.meta.env.VITE_API_BASE || ''

async function fetchAPI(path, opts = {}) {
  const res = await fetch(`${API_BASE}${path}`, opts)
  if (!res.ok) throw new Error(`${path} → ${res.status}`)
  return res.json()
}

// ── Source Selector ────────────────────────────────────────────────────────────
// 'demo' | 'upload' | 'camera'
function SourceSelector({ source, onSourceChange, onUpload }) {
  const fileRef = useRef(null)

  const handleUpload = async (file) => {
    message.loading({ content: 'Đang tải video lên...', key: 'upload' })
    try {
      const formData = new FormData()
      formData.append('video', file)
      const res = await fetch(`${API_BASE}/api/upload-video`, {
        method: 'POST',
        body: formData,
      })
      if (!res.ok) throw new Error('Upload failed')
      const data = await res.json()
      message.success({ content: `Video "${file.name}" đã sẵn sàng!`, key: 'upload' })
      onUpload(data.video_path || URL.createObjectURL(file))
    } catch (e) {
      message.error({ content: `Lỗi: ${e.message}`, key: 'upload' })
    }
    return false // prevent default upload
  }

  return (
    <div style={{
      display: 'flex', gap: 8, marginBottom: 12,
      flexWrap: 'wrap', alignItems: 'center',
    }}>
      <Text style={{ color: '#888', fontSize: 12, marginRight: 4 }}>Nguồn:</Text>

      <Tag
        icon={<VideoCameraOutlined />}
        color={source === 'demo' ? 'blue' : 'default'}
        onClick={() => onSourceChange('demo')}
        style={{ cursor: 'pointer', padding: '4px 12px', fontSize: 12 }}
      >
        Video Demo
      </Tag>

      <Upload
        beforeUpload={handleUpload}
        showUploadList={false}
        accept="video/*"
      >
        <Tag
          icon={<UploadOutlined />}
          color={source === 'upload' ? 'green' : 'default'}
          onClick={() => onSourceChange('upload')}
          style={{ cursor: 'pointer', padding: '4px 12px', fontSize: 12 }}
        >
          Tải Video Lên
        </Tag>
      </Upload>

      <Tag
        icon={<CameraOutlined />}
        color={source === 'camera' ? 'orange' : 'default'}
        onClick={() => onSourceChange('camera')}
        style={{ cursor: 'pointer', padding: '4px 12px', fontSize: 12 }}
      >
        Camera/Webcam
      </Tag>
    </div>
  )
}

// ── Camera Mode ───────────────────────────────────────────────────────────────
function CameraMode({ onSummaryUpdate }) {
  const videoRef = useRef(null)
  const canvasRef = useRef(null)
  const streamRef = useRef(null)
  const animRef = useRef(null)
  const [cameraOn, setCameraOn] = useState(false)
  const [cameraError, setCameraError] = useState(null)
  const [detections, setDetections] = useState([])
  const [summary, setSummary] = useState(null)

  const stopCamera = () => {
    if (streamRef.current) {
      streamRef.current.getTracks().forEach(t => t.stop())
      streamRef.current = null
    }
    if (animRef.current) cancelAnimationFrame(animRef.current)
    setCameraOn(false)
  }

  const startCamera = async () => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({
        video: { width: { ideal: 1280 }, height: { ideal: 720 }, facingMode: 'environment' },
        audio: false,
      })
      streamRef.current = stream
      if (videoRef.current) {
        videoRef.current.srcObject = stream
        videoRef.current.play()
      }
      setCameraOn(true)
      setCameraError(null)
    } catch (e) {
      setCameraError(e.message || 'Không truy cập được camera')
    }
  }

  // Process frames from camera
  useEffect(() => {
    if (!cameraOn) return
    const video = videoRef.current
    const canvas = canvasRef.current
    if (!video || !canvas) return
    const ctx = canvas.getContext('2d')

    const processFrame = async () => {
      if (video.readyState >= 2) {
        // Draw video frame to canvas
        if (canvas.width !== video.videoWidth) canvas.width = video.videoWidth || 640
        if (canvas.height !== video.videoHeight) canvas.height = video.videoHeight || 480
        ctx.drawImage(video, 0, 0, canvas.width, canvas.height)

        // Send frame to backend
        try {
          const blob = await new Promise(resolve => canvas.toBlob(resolve, 'image/jpeg', 0.7))
          const formData = new FormData()
          formData.append('frame', blob, 'frame.jpg')

          const res = await fetch(`${API_BASE}/api/detect-frame`, {
            method: 'POST',
            body: formData,
            timeout: 5000,
          })
          if (res.ok) {
            const data = await res.json()
            if (data.detections) setDetections(data.detections)
            if (data.summary) {
              setSummary(data.summary)
              onSummaryUpdate?.(data.summary)
            }
          }
        } catch {}

        // Draw detections on canvas overlay
        ctx.clearRect(0, 0, canvas.width, canvas.height)
        const scaleX = canvas.width / (data?.frame_width || canvas.width)
        const scaleY = canvas.height / (data?.frame_height || canvas.height)

        detections.forEach(d => {
          const [x1, y1, x2, y2] = d.bbox
          const px1 = x1 * scaleX, py1 = y1 * scaleY
          const px2 = x2 * scaleX, py2 = y2 * scaleY
          const ok = d.ppe_status?.compliant
          const col = ok ? '#00c853' : '#ff1744'
          ctx.strokeStyle = col; ctx.lineWidth = 2
          ctx.strokeRect(px1, py1, px2 - px1, py2 - py1)
          ctx.fillStyle = ok ? 'rgba(0,200,83,0.15)' : 'rgba(255,23,68,0.2)'
          ctx.fillRect(px1, py1, px2 - px1, py2 - py1)
          const label = ok ? 'OK' : [
            !d.ppe_status?.has_helmet && 'NO-HELMET',
            !d.ppe_status?.has_vest && 'NO-VEST',
          ].filter(Boolean).join('+') || 'VIOLATION'
          ctx.font = 'bold 13px monospace'
          const tw = ctx.measureText(label).width
          ctx.fillStyle = 'rgba(0,0,0,0.7)'
          ctx.fillRect(px1, py1 - 20, tw + 10, 19)
          ctx.fillStyle = col
          ctx.fillText(label, px1 + 5, py1 - 6)
        })
      }
      animRef.current = requestAnimationFrame(processFrame)
    }

    processFrame()
    return () => {
      if (animRef.current) cancelAnimationFrame(animRef.current)
      stopCamera()
    }
  }, [cameraOn])

  const color = summary?.compliance_rate >= 80 ? '#52c41a'
    : summary?.compliance_rate >= 50 ? '#faad14' : '#ff4d4f'

  return (
    <div>
      {!cameraOn ? (
        <div style={{
          width: '100%', height: 320,
          display: 'flex', flexDirection: 'column',
          alignItems: 'center', justifyContent: 'center',
          background: '#1a1a2e', color: '#555',
          borderRadius: 12, gap: 16,
        }}>
          <CameraOutlined style={{ fontSize: 48 }} />
          {cameraError ? (
            <div style={{ color: '#ff4d4f', textAlign: 'center', padding: '0 20px', fontSize: 13 }}>
              <div>⚠️ Lỗi camera</div>
              <div style={{ color: '#888', fontSize: 12, marginTop: 4 }}>{cameraError}</div>
              <Button type="primary" size="small" style={{ marginTop: 12 }} onClick={startCamera}>
                Thử lại
              </Button>
            </div>
          ) : (
            <>
              <span>Camera chưa bật</span>
              <Button type="primary" icon={<CameraOutlined />} onClick={startCamera}>
                Bật Camera
              </Button>
            </>
          )}
        </div>
      ) : (
        <div style={{ position: 'relative', borderRadius: 12, overflow: 'hidden', background: '#000' }}>
          <video
            ref={videoRef}
            autoPlay playsInline muted
            style={{ width: '100%', display: 'block', background: '#000' }}
          />
          <canvas
            ref={canvasRef}
            style={{
              position: 'absolute', top: 0, left: 0,
              width: '100%', height: '100%', pointerEvents: 'none',
            }}
          />

          <div style={{
            position: 'absolute', top: 10, left: 10,
            background: 'rgba(255,23,68,0.8)', borderRadius: 6, padding: '4px 10px',
            fontSize: 10, color: '#fff', fontFamily: 'monospace',
          }}>
            ● LIVE CAMERA
          </div>

          <div style={{
            position: 'absolute', top: 10, right: 10,
            background: 'rgba(0,0,0,0.7)', borderRadius: 6, padding: '4px 10px',
          }}>
            <Button
              size="small" danger
              onClick={stopCamera}
              style={{ fontSize: 11, padding: '0 8px', height: 24 }}
            >
              Tắt Camera
            </Button>
          </div>

          {summary && (
            <div style={{
              position: 'absolute', bottom: 10, left: 10,
              background: 'rgba(0,0,0,0.85)', borderRadius: 8,
              padding: '8px 12px', fontFamily: 'monospace', fontSize: 11,
            }}>
              <div style={{ color: '#fff' }}>👤 {summary.total_persons || 0} phát hiện</div>
              <div style={{ color: '#52c41a' }}>✅ {summary.compliant || 0} <span style={{ color: '#ff4d4f' }}>❌ {summary.violations || 0}</span></div>
              <div style={{ color, fontWeight: 700 }}>📊 {summary.compliance_rate || 0}%</div>
            </div>
          )}
        </div>
      )}
    </div>
  )
}

// ── Video Player (all modes) ───────────────────────────────────────────────────
function VideoPlayer({ onSummaryUpdate }) {
  const [source, setSource] = useState('demo')
  const [uploadedUrl, setUploadedUrl] = useState(null)
  const [videoReady, setVideoReady] = useState(false)
  const [videoError, setVideoError] = useState(null)

  const demoUrl = '/video/demo.mp4'

  const currentSrc = source === 'upload' && uploadedUrl
    ? uploadedUrl
    : demoUrl

  return (
    <div style={{ display: 'flex', flexDirection: 'column', gap: 12 }}>

      {/* Source selector */}
      <SourceSelector
        source={source}
        onSourceChange={(s) => {
          setSource(s)
          setVideoReady(false)
          setVideoError(null)
        }}
        onUpload={(url) => {
          setUploadedUrl(url)
          setSource('upload')
        }}
      />

      {/* ── TOP: Video view (demo or upload or camera) ── */}
      <div style={{ position: 'relative', borderRadius: 12, overflow: 'hidden', background: '#000' }}>
        {source === 'camera' ? (
          <CameraMode onSummaryUpdate={onSummaryUpdate} />
        ) : (
          <>
            <video
              src={currentSrc}
              controls autoPlay loop muted playsInline
              style={{ width: '100%', display: 'block', background: '#000' }}
              onCanPlay={() => setVideoReady(true)}
              onError={() => setVideoError('Không tải được video')}
            />

            <div style={{
              position: 'absolute', top: 10, left: 10,
              background: 'rgba(0,0,0,0.6)', borderRadius: 6, padding: '4px 10px',
              fontSize: 10, color: '#aaa', fontFamily: 'monospace',
            }}>
              📹 {source === 'upload' ? 'Video tải lên' : 'Video Demo'}
            </div>

            {videoError && (
              <div style={{
                position: 'absolute', inset: 0, display: 'flex',
                alignItems: 'center', justifyContent: 'center',
                background: 'rgba(0,0,0,0.8)', color: '#ff4d4f',
              }}>
                <div style={{ textAlign: 'center' }}>
                  <div>⚠️ {videoError}</div>
                  <div style={{ fontSize: 12, color: '#888', marginTop: 4 }}>
                    Thử tải video khác hoặc dùng Camera
                  </div>
                </div>
              </div>
            )}
            {!videoReady && !videoError && (
              <div style={{
                position: 'absolute', inset: 0, display: 'flex',
                alignItems: 'center', justifyContent: 'center',
                background: 'rgba(0,0,0,0.7)', color: '#aaa',
                flexDirection: 'column', gap: 8,
              }}>
                <LoadingOutlined style={{ fontSize: 32 }} />
                <span>Đang tải video...</span>
              </div>
            )}
          </>
        )}
      </div>

      {/* ── BOTTOM: Annotated frame from backend ── */}
      <div>
        <div style={{ fontSize: 11, color: '#666', marginBottom: 6, fontFamily: 'monospace', paddingLeft: 4 }}>
          📷 KẾT QUẢ NHẬN DIỆN PPE — {source === 'camera' ? 'Xử lý real-time' : 'Frame từ Backend'}
        </div>
        <AnnotatedFrame source={source} onSummaryUpdate={onSummaryUpdate} />
      </div>

    </div>
  )
}

// ── Annotated Frame ───────────────────────────────────────────────────────────
function AnnotatedFrame({ source, onSummaryUpdate }) {
  const [imgSrc, setImgSrc] = useState(null)
  const [summary, setSummary] = useState(null)
  const [lastUpdate, setLastUpdate] = useState(null)
  const [connected, setConnected] = useState(false)

  useEffect(() => {
    // Poll for annotated frame from backend
    const poll = setInterval(async () => {
      try {
        const res = await fetch(`${API_BASE}/api/frame`, { cache: 'no-cache' })
        if (res.ok) {
          const blob = await res.blob()
          setImgSrc(URL.createObjectURL(blob))
          setLastUpdate(new Date().toLocaleTimeString())
          setConnected(true)
        }
        const data = await fetchAPI('/api/summary')
        if (data.summary) {
          setSummary(data.summary)
          onSummaryUpdate?.(data.summary)
        }
      } catch {
        setConnected(false)
      }
    }, source === 'camera' ? 800 : 500)
    return () => clearInterval(poll)
  }, [source])

  const color = summary?.compliance_rate >= 80 ? '#52c41a'
    : summary?.compliance_rate >= 50 ? '#faad14' : '#ff4d4f'

  return (
    <div style={{ position: 'relative', borderRadius: 12, overflow: 'hidden', background: '#000' }}>
      {imgSrc ? (
        <img src={imgSrc} alt="Giám sát" style={{ width: '100%', display: 'block' }} />
      ) : (
        <div style={{
          width: '100%', height: 300,
          display: 'flex', alignItems: 'center', justifyContent: 'center',
          background: '#1a1a2e', color: '#555', flexDirection: 'column', gap: 12,
        }}>
          <VideoCameraOutlined style={{ fontSize: 40 }} />
          <span>Đang kết nối camera giám sát...</span>
        </div>
      )}

      <div style={{
        position: 'absolute', top: 10, left: 10,
        background: 'rgba(0,0,0,0.7)', borderRadius: 6, padding: '4px 10px',
        fontSize: 10, color: '#aaa', fontFamily: 'monospace',
      }}>
        Cập nhật: {lastUpdate || '...'}
      </div>

      <div style={{
        position: 'absolute', top: 10, right: 10,
        background: connected
          ? (summary && !summary.compliant && summary.violations > 0 ? 'rgba(255,23,68,0.8)' : 'rgba(0,0,0,0.7)')
          : 'rgba(255,140,0,0.8)',
        borderRadius: 6, padding: '4px 10px',
        fontSize: 10, color: '#fff', fontFamily: 'monospace',
      }}>
        {connected
          ? (summary && !summary.compliant && summary.violations > 0 ? '⚠ ALERT' : '● LIVE')
          : '○ CONNECTING'}
      </div>

      {summary && (
        <div style={{
          position: 'absolute', bottom: 10, left: 10,
          background: 'rgba(0,0,0,0.85)', borderRadius: 8,
          padding: '10px 14px', fontFamily: 'monospace', fontSize: 12,
        }}>
          <div style={{ color: '#fff', marginBottom: 4 }}>👤 {summary.total_persons || 0} phát hiện</div>
          <div style={{ color: '#52c41a' }}>✅ {summary.compliant || 0} <span style={{ color: '#ff4d4f' }}>❌ {summary.violations || 0}</span></div>
          <div style={{ color, marginTop: 4, fontSize: 14, fontWeight: 700 }}>📊 {summary.compliance_rate || 0}%</div>
        </div>
      )}
    </div>
  )
}

// ── Alert Item ───────────────────────────────────────────────────────────────
function AlertItem({ alert }) {
  const d = alert.detection || {}
  const ok = d.compliant
  return (
    <List.Item style={{ padding: '8px 0' }}>
      <Space align="start" style={{ width: '100%' }}>
        <Badge status={ok ? 'success' : 'error'} />
        <div style={{ flex: 1 }}>
          <Space>
            {d.has_helmet === false && <Tag color="red">NO HELMET</Tag>}
            {d.has_vest === false && <Tag color="orange">NO VEST</Tag>}
            {ok && <Tag color="green">OK</Tag>}
          </Space>
          <div style={{ fontSize: 11, color: '#999', marginTop: 2 }}>
            {alert.timestamp ? new Date(alert.timestamp).toLocaleTimeString() : '—'}
            {' · conf: '}{d.confidence?.toFixed(2) || '—'}
          </div>
        </div>
      </Space>
    </List.Item>
  )
}

// ── Stats Card ──────────────────────────────────────────────────────────────
function StatsCard({ title, value, icon, color, sub }) {
  return (
    <Card size="small" style={{ borderRadius: 12 }}>
      <Statistic
        title={<Text type="secondary" style={{ fontSize: 13 }}>{title}</Text>}
        value={value}
        valueStyle={{ color, fontSize: 28, fontWeight: 700 }}
        prefix={<span style={{ marginRight: 8 }}>{icon}</span>}
      />
      {sub && <div style={{ marginTop: 4, fontSize: 12, color: '#888' }}>{sub}</div>}
    </Card>
  )
}

// ── Main App ─────────────────────────────────────────────────────────────────
export default function App() {
  const [summary, setSummary] = useState({
    total_persons: 0, compliant: 0, violations: 0,
    no_helmet: 0, no_vest: 0, compliance_rate: 100,
  })
  const [alerts, setAlerts] = useState([])
  const [status, setStatus] = useState('connecting')
  const [alertStats, setAlertStats] = useState({})

  // Socket.IO
  useEffect(() => {
    const socket = io(API_BASE || window.location.origin, {
      transports: ['websocket', 'polling'],
      reconnectionAttempts: 5, reconnectionDelay: 2000,
    })
    socket.on('connect', () => {
      socket.emit('subscribe', { camera_id: 'demo-camera' })
      setStatus('live')
    })
    socket.on('disconnect', () => setStatus('stopped'))
    socket.on('detection_summary', (data) => {
      if (data.summary) setSummary(data.summary)
    })
    socket.on('ppe_alert', (alert) => {
      setAlerts(prev => [alert, ...prev].slice(0, 100))
      try {
        const audio = new Audio(
          'data:audio/wav;base64,'
        )
        audio.volume = 0.3
        audio.play().catch(() => {})
      } catch {}
    })
    return () => socket.disconnect()
  }, [])

  // Poll alerts
  useEffect(() => {
    const load = async () => {
      try {
        const [ad, sd] = await Promise.all([
          fetchAPI('/api/alerts?limit=20'),
          fetchAPI('/api/alerts/stats').catch(() => ({})),
        ])
        if (Array.isArray(ad)) setAlerts(ad)
        if (sd && !sd.error) setAlertStats(sd)
      } catch {}
    }
    load()
    const iv = setInterval(load, 10000)
    return () => clearInterval(iv)
  }, [])

  const col = summary.compliance_rate >= 80 ? '#52c41a'
    : summary.compliance_rate >= 50 ? '#faad14' : '#ff4d4f'

  return (
    <Layout style={{ minHeight: '100vh', background: '#0f0f1a' }}>
      <Header style={{
        background: '#1a1a2e', borderBottom: '1px solid #2a2a4a',
        display: 'flex', alignItems: 'center', justifyContent: 'space-between',
        padding: '0 24px',
      }}>
        <Space>
          <SafetyOutlined style={{ fontSize: 24, color: '#faad14' }} />
          <Title level={4} style={{ color: '#fff', margin: 0 }}>PPE Safety Monitor</Title>
          <Badge
            status={status === 'live' ? 'processing' : 'error'}
            text={<Text style={{ color: status === 'live' ? '#52c41a' : '#ff4d4f', fontSize: 12 }}>
              {status === 'live' ? 'LIVE' : 'CONNECTING'}
            </Text>}
          />
        </Space>
        <Space>
          <Tooltip title="Reload">
            <Button icon={<ReloadOutlined />} onClick={() => fetchAPI('/api/alerts?limit=20').then(d => Array.isArray(d) && setAlerts(d))}>
              Reload
            </Button>
          </Tooltip>
          <Tag style={{ background: '#16213e', border: 'none', color: '#aaa' }}>
            S1 Safety System v1.0
          </Tag>
        </Space>
      </Header>

      <Layout>
        <Content style={{ padding: 20, background: '#0f0f1a' }}>
          {/* Stats */}
          <Row gutter={[16, 16]} style={{ marginBottom: 20 }}>
            <Col xs={24} sm={12} md={6}>
              <StatsCard title="Tổng người" value={summary.total_persons} icon={<UserOutlined />} color="#1890ff" />
            </Col>
            <Col xs={24} sm={12} md={6}>
              <StatsCard title="Tuân thủ ✓" value={summary.compliant} icon={<CheckCircleOutlined />} color="#52c41a" />
            </Col>
            <Col xs={24} sm={12} md={6}>
              <StatsCard title="Vi phạm ✗" value={summary.violations} icon={<StopOutlined />} color="#ff4d4f"
                sub={summary.no_helmet > 0 ? `• Không mũ: ${summary.no_helmet}` : null}
              />
            </Col>
            <Col xs={24} sm={12} md={6}>
              <Card size="small" style={{ borderRadius: 12 }}>
                <Statistic
                  title={<Text type="secondary" style={{ fontSize: 13 }}>Tỷ lệ tuân thủ</Text>}
                  value={summary.compliance_rate} suffix="%"
                  valueStyle={{ color: col, fontSize: 28, fontWeight: 700 }}
                  prefix={<SafetyOutlined style={{ marginRight: 8 }} />}
                />
                <Progress percent={summary.compliance_rate} showInfo={false} strokeColor={col} style={{ marginTop: 8 }} />
              </Card>
            </Col>
          </Row>

          {/* Video + Alert */}
          <Row gutter={[16, 16]}>
            <Col xs={24} lg={14}>
              <Card
                title={<Space><VideoCameraOutlined />Camera Feed</Space>}
                style={{ background: '#1a1a2e', border: '1px solid #2a2a4a' }}
                styles={{ header: { color: '#fff', borderBottom: '1px solid #2a2a4a' } }}
              >
                <VideoPlayer onSummaryUpdate={setSummary} />
                <Alert
                  message="Chọn nguồn: Video Demo | Tải Video Lên | Camera/Webcam"
                  type="info" showIcon style={{ marginTop: 12 }}
                />
              </Card>
            </Col>

            <Col xs={24} lg={10}>
              <Card
                title={<Space><AlertOutlined style={{ color: '#ff4d4f' }} />Cảnh báo<Badge count={alerts.length} style={{ backgroundColor: '#ff4d4f' }} /></Space>}
                style={{ background: '#1a1a2e', border: '1px solid #2a2a4a', height: '100%' }}
                styles={{ header: { color: '#fff', borderBottom: '1px solid #2a2a4a' } }}
                bodyStyle={{ maxHeight: 500, overflow: 'auto' }}
              >
                {alerts.length === 0 ? (
                  <div style={{ textAlign: 'center', padding: 40, color: '#555' }}>
                    <SafetyOutlined style={{ fontSize: 48, marginBottom: 12 }} />
                    <div>Không có cảnh báo</div>
                    <div style={{ fontSize: 12, marginTop: 4 }}>Hệ thống hoạt động bình thường</div>
                  </div>
                ) : (
                  <List dataSource={alerts} renderItem={item => <AlertItem alert={item} />} locale={{ emptyText: 'Không có cảnh báo' }} />
                )}
              </Card>
            </Col>
          </Row>
        </Content>

        {/* Sidebar */}
        <Sider width={240} style={{ background: '#1a1a2e', borderLeft: '1px solid #2a2a4a', padding: 16 }}>
          <Title level={5} style={{ color: '#fff' }}>Thống kê 24h</Title>
          <Space direction="vertical" style={{ width: '100%' }} size={12}>
            <Card size="small" style={{ background: '#16213e' }}>
              <Statistic title={<Text style={{ color: '#aaa', fontSize: 12 }}>Tổng cảnh báo</Text>}
                value={alertStats.total || alerts.length} valueStyle={{ color: '#fff', fontSize: 24 }} />
            </Card>
            <Card size="small" style={{ background: '#16213e' }}>
              <Statistic title={<Text style={{ color: '#aaa', fontSize: 12 }}>Không đội mũ</Text>}
                value={alertStats.no_helmet || 0} valueStyle={{ color: '#ff4d4f', fontSize: 24 }} />
            </Card>
            <Card size="small" style={{ background: '#16213e' }}>
              <Statistic title={<Text style={{ color: '#aaa', fontSize: 12 }}>Không áo phản quang</Text>}
                value={alertStats.no_vest || 0} valueStyle={{ color: '#faad14', fontSize: 24 }} />
            </Card>
            <div style={{ marginTop: 16 }}>
              <Title level={5} style={{ color: '#fff' }}>Hướng dẫn</Title>
              <Card size="small" style={{ background: '#16213e', fontSize: 12 }}>
                <div style={{ color: '#aaa', lineHeight: 1.8, fontSize: 12 }}>
                  <div>📹 <b>Demo:</b> Video có sẵn</div>
                  <div>⬆ <b>Upload:</b> Tải video của bạn</div>
                  <div>📷 <b>Camera:</b> Webcam realtime</div>
                </div>
              </Card>
            </div>
          </Space>
        </Sider>
      </Layout>
    </Layout>
  )
}

