# ── S1 PPE Safety Monitor — Nginx Production Config ────────────────────────────

server {
    listen 80;
    server_name your-domain.com;  # ← Thay đổi domain

    # ── Frontend (React built files) ──────────────────────────────────────────
    location / {
        root /var/www/ppe-safety/dist;
        try_files $uri $uri/ /index.html;
        gzip on;
        gzip_types text/plain text/css application/json application/javascript text/xml application/xml;
        expires 7d;
        add_header Cache-Control "public, immutable";
    }

    # ── Backend API ─────────────────────────────────────────────────────────
    location /api/ {
        proxy_pass http://127.0.0.1:5000/api/;
        proxy_http_version 1.1;
        proxy_set_header Host $host;
        proxy_set_header X-Real-IP $remote_addr;
        proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;
        proxy_set_header X-Forwarded-Proto $scheme;
        proxy_read_timeout 120s;
        # For large video uploads
        client_max_body_size 512M;
    }

    # ── Socket.IO WebSocket ──────────────────────────────────────────────────
    location /socket.io/ {
        proxy_pass http://127.0.0.1:5000/socket.io/;
        proxy_http_version 1.1;
        proxy_set_header Upgrade $http_upgrade;
        proxy_set_header Connection "upgrade";
        proxy_set_header Host $host;
        proxy_set_header X-Real-IP $remote_addr;
        proxy_read_timeout 86400s;
    }

    # ── Video uploads (optional) ──────────────────────────────────────────────
    location /video/ {
        alias /var/www/ppe-safety/uploads/;
        # Enable video seeking (Range requests)
        max_ranges 0;
        add_header Accept-Ranges bytes;
        add_header Cache-Control "no-cache";
        # For video streaming
        proxy_pass http://127.0.0.1:5000/video/;
        proxy_http_version 1.1;
        proxy_set_header Host $host;
        # Don't buffer — stream directly
        proxy_buffering off;
        proxy_cache off;
    }

    # ── Security headers ─────────────────────────────────────────────────────
    add_header X-Frame-Options "SAMEORIGIN" always;
    add_header X-Content-Type-Options "nosniff" always;
    add_header X-XSS-Protection "1; mode=block" always;
    add_header Referrer-Policy "strict-origin-when-cross-origin" always;
}

