// ── Camera Mode ───────────────────────────────────────────────────────────────
function CameraMode({ onSummaryUpdate }) {
  const videoRef = useRef(null)
  const canvasRef = useRef(null)
  const streamRef = useRef(null)
  const animRef = useRef(null)
  const [cameraOn, setCameraOn] = useState(false)
  const [cameraError, setCameraError] = useState(null)
  const [detections, setDetections] = useState([])
  const [summary, setSummary] = useState(null)

  const stopCamera = () => {
    if (streamRef.current) {
      streamRef.current.getTracks().forEach(t => t.stop())
      streamRef.current = null
    }
    if (animRef.current) cancelAnimationFrame(animRef.current)
    setCameraOn(false)
  }

  const startCamera = async () => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({
        video: { width: { ideal: 1280 }, height: { ideal: 720 }, facingMode: 'environment' },
        audio: false,
      })
      streamRef.current = stream
      if (videoRef.current) {
        videoRef.current.srcObject = stream
        videoRef.current.play()
      }
      setCameraOn(true)
      setCameraError(null)
    } catch (e) {
      setCameraError(e.message || 'Không truy cập được camera')
    }
  }

  // Process frames from camera
  useEffect(() => {
    if (!cameraOn) return
    const video = videoRef.current
    const canvas = canvasRef.current
    if (!video || !canvas) return
    const ctx = canvas.getContext('2d')

    const processFrame = async () => {
      if (video.readyState >= 2) {
        // Draw video frame to canvas
        if (canvas.width !== video.videoWidth) canvas.width = video.videoWidth || 640
        if (canvas.height !== video.videoHeight) canvas.height = video.videoHeight || 480
        ctx.drawImage(video, 0, 0, canvas.width, canvas.height)

        // Send frame to backend
        try {
          const blob = await new Promise(resolve => canvas.toBlob(resolve, 'image/jpeg', 0.7))
          const formData = new FormData()
          formData.append('frame', blob, 'frame.jpg')


