          const res = await fetch(`${API_BASE}/api/detect-frame`, {
            method: 'POST',
            body: formData,
            timeout: 5000,
          })
          if (res.ok) {
            const data = await res.json()
            if (data.detections) setDetections(data.detections)
            if (data.summary) {
              setSummary(data.summary)
              onSummaryUpdate?.(data.summary)
            }
          }
        } catch {}

        // Draw detections on canvas overlay
        ctx.clearRect(0, 0, canvas.width, canvas.height)

        detections.forEach(d => {
          const [x1, y1, x2, y2] = d.bbox
          const px1 = x1, py1 = y1
          const pw = x2 - x1, ph = y2 - y1
          const ok = d.ppe_status?.compliant
          const col = ok ? '#00c853' : '#ff1744'
          ctx.strokeStyle = col; ctx.lineWidth = 2
          ctx.strokeRect(px1, py1, pw, ph)
          ctx.fillStyle = ok ? 'rgba(0,200,83,0.15)' : 'rgba(255,23,68,0.2)'
          ctx.fillRect(px1, py1, pw, ph)
          const label = ok ? 'OK' : [
            !d.ppe_status?.has_helmet && 'NO-HELMET',
            !d.ppe_status?.has_vest && 'NO-VEST',
          ].filter(Boolean).join('+') || 'VIOLATION'
          ctx.font = 'bold 13px monospace'
          const tw = ctx.measureText(label).width
          ctx.fillStyle = 'rgba(0,0,0,0.7)'
          ctx.fillRect(px1, py1 - 20, tw + 10, 19)
          ctx.fillStyle = col
          ctx.fillText(label, px1 + 5, py1 - 6)
        })
      }
      animRef.current = requestAnimationFrame(processFrame)
    }

    processFrame()
    return () => {
      if (animRef.current) cancelAnimationFrame(animRef.current)
      stopCamera()
    }
  }, [cameraOn])

  const color = summary?.compliance_rate >= 80 ? '#52c41a'
    : summary?.compliance_rate >= 50 ? '#faad14' : '#ff4d4f'

  return (
    <div>
      {!cameraOn ? (
        <div style={{
          width: '100%', height: 320,
          display: 'flex', flexDirection: 'column',
          alignItems: 'center', justifyContent: 'center',
          background: '#1a1a2e', color: '#555',
          borderRadius: 12, gap: 16,
        }}>
          <CameraOutlined style={{ fontSize: 48 }} />
          {cameraError ? (
            <div style={{ color: '#ff4d4f', textAlign: 'center', padding: '0 20px', fontSize: 13 }}>
              <div>⚠️ Lỗi camera</div>
              <div style={{ color: '#888', fontSize: 12, marginTop: 4 }}>{cameraError}</div>
              <Button type="primary" size="small" style={{ marginTop: 12 }} onClick={startCamera}>
                Thử lại
              </Button>
            </div>
          ) : (
            <>
              <span>Camera chưa bật</span>
              <Button type="primary" icon={<CameraOutlined />} onClick={startCamera}>
                Bật Camera
              </Button>
            </>
          )}
        </div>
      ) : (
        <div style={{ position: 'relative', borderRadius: 12, overflow: 'hidden', background: '#000' }}>
          <video
            ref={videoRef}
            autoPlay playsInline muted
            style={{ width: '100%', display: 'block', background: '#000' }}
          />
          <canvas
            ref={canvasRef}
            style={{
              position: 'absolute', top: 0, left: 0,
              width: '100%', height: '100%', pointerEvents: 'none',
            }}
          />

          <div style={{
            position: 'absolute', top: 10, left: 10,
            background: 'rgba(255,23,68,0.8)', borderRadius: 6, padding: '4px 10px',
            fontSize: 10, color: '#fff', fontFamily: 'monospace',
          }}>
            ● LIVE CAMERA
          </div>

          <div style={{
            position: 'absolute', top: 10, right: 10,
            background: 'rgba(0,0,0,0.7)', borderRadius: 6, padding: '4px 10px',
          }}>
            <Button
              size="small" danger
              onClick={stopCamera}
              style={{ fontSize: 11, padding: '0 8px', height: 24 }}
            >
