  const [settingsOpen, setSettingsOpen] = useState(false)
  const [ipCameraUrl, setIpCameraUrl] = useState('')

  const filteredAlerts = alerts.filter(a => {
    if (alertFilter === 'all') return true
    const d = a.detection || {}
    if (alertFilter === 'no_helmet') return d.has_helmet === false
    if (alertFilter === 'no_vest') return d.has_vest === false
    if (alertFilter === 'ok') return d.compliant
    return true
  })

  const exportCSV = () => {
    const rows = [['Timestamp', 'Type', 'Has Helmet', 'Has Vest', 'Compliant', 'Confidence', 'Camera']]
    filteredAlerts.forEach(a => {
      const d = a.detection || {}
      rows.push([
        a.timestamp || '',
        a.type || '',
        d.has_helmet === undefined ? '' : d.has_helmet,
        d.has_vest === undefined ? '' : d.has_vest,
        d.compliant || false,
        d.confidence || '',
        a.camera_id || '',
      ])
    })
    const csv = rows.map(r => r.join(',')).join('\n')
    const blob = new Blob([csv], { type: 'text/csv' })
    const url = URL.createObjectURL(blob)
    const a = document.createElement('a')
    a.href = url
    a.download = `ppe-alerts-${new Date().toISOString().slice(0, 10)}.csv`
    a.click()
    URL.revokeObjectURL(url)
  }

