@app.route("/api/stats/reset", methods=["POST"])
def reset_stats():
    """Reset detection statistics and history."""
    global detector
    # Reset detector internal stats
    detector._stats.clear()
    # Clear history
    with _history_lock:
        _detection_history.clear()
    # Clear processor stats if running
    if processor and hasattr(processor, 'detector'):
        processor.detector._stats.clear()
    # Reset processor frame count
    if processor:
        processor._frame_count = 0
