// ── Simple SVG Timeline Chart ─────────────────────────────────────────────────
function TimelineChart({ history }) {
  if (!history || history.length < 2) {
    return <div style={{ height: 60, display: 'flex', alignItems: 'center', justifyContent: 'center', color: '#555', fontSize: 11 }}>Chưa có dữ liệu timeline</div>
  }

  const W = 100, H = 50
  const n = history.length
  const vals = history.map(h => h.total || 0)
  const max = Math.max(...vals, 1)
  const pts = vals.map((v, i) => `${(i / (n - 1)) * W},${H - (v / max) * H}`).join(' ')
  const total = history.reduce((s, h) => s + (h.total || 0), 0)
  const violations = history.reduce((s, h) => s + (h.violations || 0), 0)

  return (
    <div style={{ marginTop: 8 }}>
      <div style={{ fontSize: 11, color: '#888', marginBottom: 4 }}>
        Timeline ({n} frames: {total} phát hiện, <span style={{ color: violations > 0 ? '#ff4d4f' : '#52c41a' }}>{violations} vi phạm</span>)
      </div>
      <svg width="100%" height={H} viewBox={`0 0 ${W} ${H}`} preserveAspectRatio="none">
        <polyline
          points={pts}
          fill="none"
          stroke="#1890ff"
          strokeWidth="1.5"
          strokeLinejoin="round"
          strokeLinecap="round"
        />
        {vals.map((v, i) => {
          const x = (i / (n - 1)) * W
          const y = H - (v / max) * H
          if (!v) return null
          return <circle key={i} cx={x} cy={y} r="1.5" fill="#1890ff" />
        })}
      </svg>
    </div>
  )
}

